import os
import json
import base64
from io import BytesIO
from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import face_recognition
from pathlib import Path
import pickle

app = Flask(__name__)

class FacialRecognitionModel:
    def __init__(self, training_data_dir='employee_photos', model_path='face_model.pkl'):
        self.training_data_dir = training_data_dir
        self.model_path = model_path
        self.known_face_encodings = []
        self.known_face_names = []
        
    def train(self):
        """Train the model on employee photos"""
        self.known_face_encodings = []
        self.known_face_names = []
        
        if not os.path.exists(self.training_data_dir):
            os.makedirs(self.training_data_dir)
            print(f"Created training directory: {self.training_data_dir}")
            return
        
        for person_dir in os.listdir(self.training_data_dir):
            person_path = os.path.join(self.training_data_dir, person_dir)
            
            if not os.path.isdir(person_path):
                continue
                
            for image_file in os.listdir(person_path):
                if not image_file.lower().endswith(('.png', '.jpg', '.jpeg')):
                    continue
                    
                image_path = os.path.join(person_path, image_file)
                
                try:
                    image = face_recognition.load_image_file(image_path)
                    face_encodings = face_recognition.face_encodings(image)
                    
                    if face_encodings:
                        self.known_face_encodings.append(face_encodings[0])
                        self.known_face_names.append(person_dir)
                        print(f"Trained on: {person_dir}/{image_file}")
                    else:
                        print(f"No face found in: {person_dir}/{image_file}")
                except Exception as e:
                    print(f"Error processing {image_path}: {str(e)}")
        
        self.save_model()
        print(f"Training complete. Total faces: {len(self.known_face_encodings)}")
    
    def save_model(self):
        """Save trained model to disk"""
        model_data = {
            'encodings': self.known_face_encodings,
            'names': self.known_face_names
        }
        with open(self.model_path, 'wb') as f:
            pickle.dump(model_data, f)
        print(f"Model saved to {self.model_path}")
    
    def load_model(self):
        """Load trained model from disk"""
        if os.path.exists(self.model_path):
            with open(self.model_path, 'rb') as f:
                model_data = pickle.load(f)
            self.known_face_encodings = model_data['encodings']
            self.known_face_names = model_data['names']
            print(f"Model loaded from {self.model_path}")
            return True
        return False
    
    def recognize_face(self, image_data):
        """Recognize face and return confidence scores for all classes"""
        if isinstance(image_data, str):
            if image_data.startswith('data:image'):
                image_data = image_data.split(',')[1]
            image_bytes = base64.b64decode(image_data)
            image = Image.open(BytesIO(image_bytes))
            image = np.array(image)
        elif isinstance(image_data, bytes):
            image = Image.open(BytesIO(image_data))
            image = np.array(image)
        else:
            image = image_data
        
        face_locations = face_recognition.face_locations(image)
        face_encodings = face_recognition.face_encodings(image, face_locations)
        
        results = []
        
        for face_encoding, face_location in zip(face_encodings, face_locations):
            face_distances = face_recognition.face_distance(
                self.known_face_encodings, face_encoding
            )
            
            confidence_scores = self._calculate_confidence_distribution(face_distances)
            
            best_match_index = np.argmin(face_distances)
            best_match_name = self.known_face_names[best_match_index]
            best_match_confidence = confidence_scores[best_match_name]
            
            results.append({
                'face_location': {
                    'top': int(face_location[0]),
                    'right': int(face_location[1]),
                    'bottom': int(face_location[2]),
                    'left': int(face_location[3])
                },
                'best_match': best_match_name,
                'best_match_confidence': float(best_match_confidence),
                'all_confidence_scores': confidence_scores,
                'detailed_probabilities': self._get_detailed_probabilities(face_distances)
            })
        
        return results
    
    def _calculate_confidence_distribution(self, face_distances):
        """Calculate confidence scores for all known faces"""
        tolerance = 0.6
        confidence_scores = {}
        
        unique_names = list(set(self.known_face_names))
        
        for name in unique_names:
            name_indices = [i for i, n in enumerate(self.known_face_names) if n == name]
            name_distances = [face_distances[i] for i in name_indices]
            
            min_distance = min(name_distances)
            
            if min_distance <= tolerance:
                confidence = 1.0 - (min_distance / tolerance)
            else:
                confidence = max(0.0, 1.0 - min_distance)
            
            confidence_scores[name] = float(confidence)
        
        total_confidence = sum(confidence_scores.values())
        if total_confidence > 0:
            normalized_scores = {
                name: (score / total_confidence) 
                for name, score in confidence_scores.items()
            }
        else:
            normalized_scores = confidence_scores
        
        return normalized_scores
    
    def _get_detailed_probabilities(self, face_distances):
        """Get detailed probability distribution with all statistical measures"""
        unique_names = list(set(self.known_face_names))
        detailed_probs = {}
        
        for name in unique_names:
            name_indices = [i for i, n in enumerate(self.known_face_names) if n == name]
            name_distances = [face_distances[i] for i in name_indices]
            
            detailed_probs[name] = {
                'min_distance': float(min(name_distances)),
                'max_distance': float(max(name_distances)),
                'mean_distance': float(np.mean(name_distances)),
                'std_distance': float(np.std(name_distances)),
                'sample_count': len(name_distances),
                'distances': [float(d) for d in name_distances]
            }
        
        return detailed_probs


model = FacialRecognitionModel()

@app.route('/api/train', methods=['POST'])
def train_model():
    """Endpoint to train the model"""
    try:
        model.train()
        return jsonify({
            'status': 'success',
            'message': 'Model trained successfully',
            'total_faces': len(model.known_face_encodings),
            'unique_employees': len(set(model.known_face_names))
        })
    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': str(e)
        }), 500

@app.route('/api/recognize', methods=['POST'])
def recognize():
    """Endpoint to recognize faces in an image"""
    try:
        if not model.known_face_encodings:
            if not model.load_model():
                return jsonify({
                    'status': 'error',
                    'message': 'Model not trained. Please train the model first.'
                }), 400
        
        if 'image' in request.files:
            image_file = request.files['image']
            image = Image.open(image_file.stream)
            image_data = np.array(image)
        elif 'image_data' in request.json:
            image_data = request.json['image_data']
        else:
            return jsonify({
                'status': 'error',
                'message': 'No image provided'
            }), 400
        
        results = model.recognize_face(image_data)
        
        return jsonify({
            'status': 'success',
            'faces_detected': len(results),
            'results': results
        })
    
    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': str(e)
        }), 500

@app.route('/api/model/info', methods=['GET'])
def model_info():
    """Get information about the trained model"""
    try:
        if not model.known_face_encodings:
            model.load_model()
        
        unique_employees = list(set(model.known_face_names))
        employee_counts = {
            name: model.known_face_names.count(name) 
            for name in unique_employees
        }
        
        return jsonify({
            'status': 'success',
            'total_faces': len(model.known_face_encodings),
            'unique_employees': len(unique_employees),
            'employees': unique_employees,
            'samples_per_employee': employee_counts
        })
    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': str(e)
        }), 500

@app.route('/api/add_employee', methods=['POST'])
def add_employee():
    """Add a new employee with photos"""
    try:
        if 'name' not in request.form:
            return jsonify({
                'status': 'error',
                'message': 'Employee name required'
            }), 400
        
        employee_name = request.form['name']
        employee_dir = os.path.join(model.training_data_dir, employee_name)
        
        if not os.path.exists(employee_dir):
            os.makedirs(employee_dir)
        
        files = request.files.getlist('photos')
        saved_files = []
        
        for i, file in enumerate(files):
            if file and file.filename:
                ext = os.path.splitext(file.filename)[1]
                filename = f"{employee_name}_{i}{ext}"
                filepath = os.path.join(employee_dir, filename)
                file.save(filepath)
                saved_files.append(filename)
        
        return jsonify({
            'status': 'success',
            'message': f'Added {len(saved_files)} photos for {employee_name}',
            'saved_files': saved_files,
            'note': 'Run /api/train to update the model'
        })
    
    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': str(e)
        }), 500

